const axios = require('axios');
const { CookieJar } = require('tough-cookie');
const { wrapper } = require('axios-cookiejar-support');
require('dotenv').config();
const WP_URL = process.env.WP_URL || 'https://100plus.kr';
const WP_USER = process.env.WP_USER || 'wide1002@gmail.com';
const WP_PASS = process.env.WP_PASS || 'g7bakkyWMD';

const targetSlugs = [
    '의학전문칼럼-통풍-원인-요산-수치-낮추는-퓨린-식단',
    '심층의학칼럼-마카-maca-효능과-부작용-완벽-가이드',
    '심층의학칼럼-nac-n-아세틸시스테인-효능과-부작용-완',
    '의학가이드-비타민b군-총정리-8가지-비타민의-역할과',
    '의학전문칼럼-탈모-예방을-위한-영양제와-올바른-두',
    '의학전문칼럼-비타민d-결핍-증상과-올바른-보충법'
];

const keywords = ['통풍 원인', '마카', 'NAC', '비타민B군', '탈모 예방', '비타민D 결핍'];

async function run() {
    console.log("🗑️ 6개 글의 이상한 이미지 제거 시작...\n");
    const jar = new CookieJar();
    const client = wrapper(axios.create({ jar, withCredentials: true }));
    await client.get(`${WP_URL}/wp-login.php`);
    const params = new URLSearchParams({ log: WP_USER, pwd: WP_PASS, 'wp-submit': 'Log In', redirect_to: `${WP_URL}/wp-admin/`, testcookie: '1' });
    await client.post(`${WP_URL}/wp-login.php`, params);
    const resAdmin = await client.get(`${WP_URL}/wp-admin/`);
    const nonce = resAdmin.data.match(/"nonce":"([^"]+)"/)[1];

    const resPublish = await client.get(`${WP_URL}/wp-json/wp/v2/posts?per_page=100&status=publish`, { headers: {'X-WP-Nonce': nonce} });
    const resFuture = await client.get(`${WP_URL}/wp-json/wp/v2/posts?per_page=100&status=future`, { headers: {'X-WP-Nonce': nonce} });
    const allPosts = [...resPublish.data, ...resFuture.data];

    let removed = 0;
    for (const kw of keywords) {
        const post = allPosts.find(p => p.title.rendered.toLowerCase().includes(kw.toLowerCase()));

        if (!post) {
            console.log(`⚠️ 키워드 매칭 실패: ${kw}`);
            continue;
        }

        console.log(`📝 [${removed+1}] ${post.title.rendered}`);
        console.log(`   현재 이미지 ID: ${post.featured_media}`);

        if (post.featured_media && post.featured_media > 0) {
            try {
                const res = await client.post(
                    `${WP_URL}/wp-json/wp/v2/posts/${post.id}`,
                    { featured_media: 0 },
                    { headers: {'X-WP-Nonce': nonce, 'Content-Type': 'application/json'} }
                );
                if (res.status === 200) {
                    console.log(`   ✅ 이미지 제거 완료!`);
                    removed++;
                }
            } catch(e) {
                console.log(`   ❌ 에러: ${e.message}`);
            }
        } else {
            console.log(`   ℹ️ 이미 이미지가 없습니다.`);
        }
    }

    console.log(`\n🏆 총 ${removed}개 글에서 이미지가 제거되었습니다!`);
}
run().catch(console.error);

