const axios = require('axios');
const { CookieJar } = require('tough-cookie');
const { wrapper } = require('axios-cookiejar-support');
require('dotenv').config();
const WP_URL = process.env.WP_URL || 'https://100plus.kr';
const WP_USER = process.env.WP_USER || 'wide1002@gmail.com';
const WP_PASS = process.env.WP_PASS || 'g7bakkyWMD';

const content = `
<p>"바람만 스쳐도 아프다." 통풍(痛風)이라는 이름의 유래입니다. 겪어보지 않은 사람은 그 고통을 절대 모른다고 하죠. 한밤중에 발가락이 퉁퉁 붓고 붉게 달아오르며, 마치 칼로 찌르는 듯한 통증이 밀려온다면 십중팔구 통풍입니다.</p>
<p>제가 상담을 하다 보면 "선생님, 저 이제 평생 고기도 못 먹고 풀만 먹어야 하나요?"라며 울상을 지으시는 분들이 많습니다. 결론부터 말씀드리면 <strong>그렇지 않습니다.</strong> 통풍의 핵심 원인인 '요산'과 '퓨린'의 관계만 정확히 알면, 먹는 즐거움을 유지하면서도 통풍의 공포에서 벗어날 수 있습니다.</p>

<h2>통풍의 원인: 내 몸에 쌓인 '요산'이라는 유리조각</h2>
<p>통풍을 이해하려면 먼저 <strong>'요산(Uric Acid)'</strong>이라는 물질을 알아야 합니다. 요산은 우리 몸의 세포가 수명을 다하거나, 우리가 음식을 먹고 소화시키는 과정에서 나오는 '단백질 찌꺼기'입니다.</p>
<p>정상적인 상태라면 이 요산은 신장(콩팥)을 거쳐 소변으로 얌전하게 빠져나갑니다. 그런데 요산이 너무 많이 만들어지거나, 신장이 이걸 제대로 배출하지 못하면 문제가 생깁니다. 혈액 속에 넘쳐나던 요산이 <strong>뾰족한 유리조각 같은 결정체</strong>로 뭉쳐서 관절(특히 엄지발가락) 주변에 쌓이게 되고, 우리 몸의 면역세포가 이걸 공격하면서 엄청난 염증과 통증을 일으키는 것, 이것이 바로 통풍입니다.</p>

<h2>퓨린(Purine)과 요산의 관계: 왜 퓨린을 조심해야 할까?</h2>
<p>그럼 요산은 대체 어디서 많이 만들어질까요? 바로 <strong>'퓨린(Purine)'</strong>이라는 성분이 분해될 때 요산이 대량으로 생성됩니다.</p>
<p>과거에 잘못 작성된 정보들을 보면 "퓨린이 요산을 낮춰준다"는 황당한 내용이 돌아다니기도 하는데, <strong>이건 완전히 틀린 정보이며 매우 위험합니다.</strong> 퓨린이 많이 든 음식을 먹을수록 내 몸속의 요산 수치는 급격히 올라갑니다. 따라서 통풍 환자라면 <strong>퓨린이 적은 식단(저퓨린 식단)</strong>을 유지하는 것이 치료의 절대적인 첫걸음입니다.</p>

<h2>통풍 환자가 피해야 할 '고(高)퓨린' 음식 3가지</h2>
<p>이 세 가지는 통풍 발작이 있을 때만큼은 무조건 피하셔야 합니다.</p>
<ul>
<li><strong>1. 술, 특히 맥주</strong>: "치맥"은 통풍 환자에게 최악의 조합입니다. 맥주 자체에 퓨린이 엄청나게 많을 뿐만 아니라, 알코올 성분 자체가 신장이 요산을 배출하는 것을 방해합니다. 소주나 와인도 마찬가지로 알코올이 들어있어 좋지 않습니다.</li>
<li><strong>2. 동물의 내장류</strong>: 곱창, 대창, 막창, 간, 순대 등은 퓨린의 덩어리라고 보셔도 무방합니다. </li>
<li><strong>3. 진한 고기 국물과 등푸른 생선</strong>: 푹 고아낸 사골국, 갈비탕 국물에는 고기의 퓨린이 고스란히 녹아 있습니다. 또한 고등어, 꽁치, 정어리 같은 등푸른 생선과 오징어, 새우, 조개류도 퓨린 함량이 높습니다.</li>
</ul>

<h2>통풍 환자를 살리는 '요산 배출' 음식들</h2>
<p>그럼 도대체 뭘 먹어야 할까요? 다행히 요산을 낮춰주고 통풍에 도움을 주는 맛있는 음식들도 많습니다.</p>
<ul>
<li><strong>물 (가장 중요!)</strong>: 하루 2리터 이상의 물을 마시는 것은 요산을 소변으로 씻어내는 가장 확실하고 부작용 없는 방법입니다.</li>
<li><strong>저지방 유제품</strong>: 우유나 치즈, 요거트에 들어있는 단백질은 퓨린이 거의 없고, 오히려 요산의 배설을 돕는다고 알려져 있습니다.</li>
<li><strong>체리(Tart Cherry)</strong>: 체리에는 항산화 물질이 풍부해 관절의 염증을 줄여주고 요산 수치를 낮추는 데 효과적이라는 연구 결과가 많습니다.</li>
<li><strong>블랙커피</strong>: 하루 1~2잔의 설탕과 프림이 없는 블랙커피는 이뇨 작용을 도와 요산 배출에 이롭습니다.</li>
<li><strong>대부분의 채소류</strong>: 시금치나 버섯, 아스파라거스에 퓨린이 약간 있긴 하지만, 식물성 퓨린은 통풍 발작 위험을 높이지 않는다는 연구가 많으니 안심하고 드셔도 됩니다.</li>
</ul>

<h2>전문작가의 현실적인 조언</h2>
<p>통풍 진단을 받았다고 해서 평생 고기를 아예 못 먹는 것은 아닙니다. 급성 발작이 지나가고 병원에서 처방받은 요산 저하제(알로푸리놀 등)를 꾸준히 드시면서 요산 수치가 6.0mg/dL 이하로 안정적으로 유지된다면, 가끔은 적당량의 살코기를 즐기실 수 있습니다.</p>
<p>가장 중요한 것은 <strong>'과식과 비만'을 피하는 것</strong>입니다. 살이 찌면 몸속에서 요산이 더 많이 만들어집니다. 오늘부터 맥주 대신 시원한 물을 한 잔 더 마시고, 기름진 내장탕 대신 담백한 채소 위주의 식사를 해보시는 건 어떨까요? 작은 습관의 변화가 밤의 끔찍한 고통으로부터 여러분을 지켜줄 것입니다.</p>
`;

