async function run() {
    console.log("🚀 연락하기(Contact) 페이지 업데이트 시작...");
    const jar = new CookieJar();
    const client = wrapper(axios.create({ jar, withCredentials: true }));

    await client.get(`${WP_URL}/wp-login.php`);
    const params = new URLSearchParams({ 
        log: WP_USER, pwd: WP_PASS, 'wp-submit': 'Log In', 
        redirect_to: `${WP_URL}/wp-admin/`, testcookie: '1' 
    });
    await client.post(`${WP_URL}/wp-login.php`, params);

    const resAdmin = await client.get(`${WP_URL}/wp-admin/`);
    const nonceMatch = resAdmin.data.match(/"nonce":"([^"]+)"/);
    if (!nonceMatch) {
        console.log("❌ Nonce 추출 실패");
        return;
    }
    const nonce = nonceMatch[1];

    // 페이지 목록 가져오기
    const resPages = await client.get(`${WP_URL}/wp-json/wp/v2/pages?per_page=100`, { headers: {'X-WP-Nonce': nonce} });

    // contact 페이지 찾기
    const contactPage = resPages.data.find(p => p.slug === 'contact' || p.title.rendered.includes('연락하기'));

    if (contactPage) {
        console.log(`📝 찾은 페이지: ${contactPage.title.rendered} (ID: ${contactPage.id})`);
        try {
            const res = await client.post(
                `${WP_URL}/wp-json/wp/v2/pages/${contactPage.id}`, 
                { content: newContent }, 
                { headers: {'X-WP-Nonce': nonce, 'Content-Type': 'application/json'} }
