async function auditPosts() {
    try {
        const cookieJar = new CookieJar();
        const client = wrapper(axios.create({ jar: cookieJar, withCredentials: true }));

        await client.get(`${WP_URL}/wp-login.php`);
        const loginParams = new URLSearchParams();
        loginParams.append('log', WP_USER);
        loginParams.append('pwd', WP_PASS);
        loginParams.append('wp-submit', 'Log In');
        loginParams.append('redirect_to', `${WP_URL}/wp-admin/`);
        loginParams.append('testcookie', '1');
        await client.post(`${WP_URL}/wp-login.php`, loginParams, {
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
        });

        const resAdmin = await client.get(`${WP_URL}/wp-admin/`);
        const nonceMatch = resAdmin.data.match(/"nonce":"([^"]+)"/);
        if (!nonceMatch) throw new Error("Nonce not found");
        const nonce = nonceMatch[1];
        const headers = { 'X-WP-Nonce': nonce, 'Content-Type': 'application/json' };

        let allPosts = [];
        let page = 1;
        let totalPages = 1;

        console.log("Fetching all posts...");
        while (page <= totalPages) {
            const res = await client.get(`${WP_URL}/wp-json/wp/v2/posts?per_page=100&page=${page}`, { headers });
            allPosts = allPosts.concat(res.data);
            totalPages = parseInt(res.headers['x-wp-totalpages'], 10);
            page++;
        }

        console.log(`Total posts fetched: ${allPosts.length}`);

        const auditResult = {
            total: allPosts.length,
            published: 0,
            drafts: 0,
            missingTags: [],
            badFormat: [], // missing core summary block or standard h3 tags
            noFeaturedMedia: []
        };

        allPosts.forEach(post => {
            if (post.status === 'publish') auditResult.published++;
            else auditResult.drafts++;

            if (!post.tags || post.tags.length === 0) {
                auditResult.missingTags.push(post.id);
            }

            const content = post.content.rendered || "";
            // Check for standard summary block
            const hasSummary = content.includes('📌 핵심 요약');
            if (!hasSummary) {
                auditResult.badFormat.push(post.id);
            }

            if (!post.featured_media || post.featured_media === 0) {
                auditResult.noFeaturedMedia.push(post.id);
            }
        });

        fs.writeFileSync('post_audit.json', JSON.stringify(auditResult, null, 2));
        console.log("Audit complete. Saved to post_audit.json.");

    } catch (err) {
        console.error(err.message);
    }
}
auditPosts();

