            if (isShort || noTags) {
                targets.push({
                    id: post.id,
                    title: post.title.rendered,
                    status: post.status,
                    isShort: isShort,
                    length: textContent.length,
                    noTags: noTags
                });
            }
        });

        fs.writeFileSync('target_posts.json', JSON.stringify(targets, null, 2));
        console.log(`Found ${targets.length} target posts. Saved to target_posts.json.`);

    } catch (err) {
