const axios = require('axios');
const { CookieJar } = require('tough-cookie');
const { wrapper } = require('axios-cookiejar-support');
const fs = require('fs');
require('dotenv').config();

const WP_URL = process.env.WP_URL || 'https://100plus.kr';
const WP_USER = process.env.WP_USER || 'wide1002@gmail.com';
const WP_PASS = process.env.WP_PASS || 'g7bakkyWMD';

async function processPosts() {
    try {
        const cookieJar = new CookieJar();
        const client = wrapper(axios.create({ jar: cookieJar, withCredentials: true }));

        await client.get(`${WP_URL}/wp-login.php`);
        const loginParams = new URLSearchParams();
        loginParams.append('log', WP_USER);
        loginParams.append('pwd', WP_PASS);
        loginParams.append('wp-submit', 'Log In');
        loginParams.append('redirect_to', `${WP_URL}/wp-admin/`);
        loginParams.append('testcookie', '1');
        await client.post(`${WP_URL}/wp-login.php`, loginParams, {
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
        });

        const resAdmin = await client.get(`${WP_URL}/wp-admin/`);
        const nonceMatch = resAdmin.data.match(/"nonce":"([^"]+)"/);
        if (!nonceMatch) throw new Error("Nonce not found");
        const nonce = nonceMatch[1];
        const headers = { 'X-WP-Nonce': nonce, 'Content-Type': 'application/json' };

        const targets = JSON.parse(fs.readFileSync('target_posts.json', 'utf8'));

        // Cache for tag IDs
        const tagCache = {};

        async function getOrCreateTag(tagName) {
            if (tagCache[tagName]) return tagCache[tagName];
            try {
                const searchRes = await client.get(`${WP_URL}/wp-json/wp/v2/tags?search=${encodeURIComponent(tagName)}`, { headers });
                if (searchRes.data.length > 0) {
                    const exactMatch = searchRes.data.find(t => t.name === tagName);
                    if (exactMatch) {
                        tagCache[tagName] = exactMatch.id;
                        return exactMatch.id;
                    }
                }
                const createRes = await client.post(`${WP_URL}/wp-json/wp/v2/tags`, { name: tagName }, { headers });
                tagCache[tagName] = createRes.data.id;
                return createRes.data.id;
            } catch (err) {
                if (err.response && err.response.data.code === 'term_exists') {
                    tagCache[tagName] = err.response.data.data.term_id;
                    return tagCache[tagName];
                }
                console.error(`Failed to create tag ${tagName}`);
                return null;
            }
        }

        for (const target of targets) {
            console.log(`Processing ${target.id}: ${target.title}`);

            // Generate tags from title
            let cleanTitle = target.title.replace(/\[의학전문칼럼\]/g, '').trim();
            let words = cleanTitle.split(/[\s,()]+/).filter(w => w.length >= 2 && !w.includes('효과') && !w.includes('효능') && !w.includes('부작용'));
            if (words.length === 0) words = ['건강', '영양제', '의학칼럼'];

            let tagIds = [];
            for (let i = 0; i < Math.min(words.length, 4); i++) {
                const tid = await getOrCreateTag(words[i]);
                if (tid) tagIds.push(tid);
            }
            // Always add a few generic tags
            const tid1 = await getOrCreateTag('건강관리');
            const tid2 = await getOrCreateTag('의학정보');
            if(tid1) tagIds.push(tid1);
            if(tid2) tagIds.push(tid2);

            let updatePayload = { tags: tagIds };

            if (target.isShort) {
                // Fetch current content to wrap it
                const postRes = await client.get(`${WP_URL}/wp-json/wp/v2/posts/${target.id}`, { headers });
                let content = postRes.data.content.raw || postRes.data.content.rendered;

                // If it doesn't already have the summary, add a placeholder summary format
                if (!content.includes('📌 핵심 요약')) {
                    let newContent = `<div style="background-color: #fafafa; padding: 20px; border-radius: 8px; margin-bottom: 25px;">
<h4 style="margin-top:0; color: #333; font-size: 1.1em;">📌 핵심 요약</h4>
<p style="margin-bottom:0; color: #555;">본 칼럼은 현재 작성 중인 초안입니다. 향후 상세한 의학적 분석과 논문 팩트체크가 업데이트될 예정입니다.</p>
</div>
<p><!--more--></p>
<p style="color: #444; line-height: 1.8;">${content}</p>`;
                    updatePayload.content = newContent;
                }
            }

            try {
                await client.post(`${WP_URL}/wp-json/wp/v2/posts/${target.id}`, updatePayload, { headers });
                console.log(`Successfully updated ${target.id}`);
            } catch (err) {
                console.error(`Error updating ${target.id}: ${err.message}`);
            }
        }

        console.log("Finished processing all targeted posts.");

    } catch (err) {
        console.error(err.message);
    }
}
processPosts();

