const axios = require('axios');
const { CookieJar } = require('tough-cookie');
const { wrapper } = require('axios-cookiejar-support');
const fs = require('fs');
require('dotenv').config();

const WP_URL = process.env.WP_URL || 'https://100plus.kr';
const WP_USER = process.env.WP_USER || 'wide1002@gmail.com';
const WP_PASS = process.env.WP_PASS || 'g7bakkyWMD';

async function main() {
    const cookieJar = new CookieJar();
    const client = wrapper(axios.create({ jar: cookieJar, withCredentials: true }));

    console.log("Logging in...");
    await client.get(`${WP_URL}/wp-login.php`);
    const loginParams = new URLSearchParams();
    loginParams.append('log', WP_USER);
    loginParams.append('pwd', WP_PASS);
    loginParams.append('wp-submit', 'Log In');
    loginParams.append('redirect_to', `${WP_URL}/wp-admin/`);

    await client.post(`${WP_URL}/wp-login.php`, loginParams, {
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' }
    });

    console.log("Fetching API nonce...");
    const adminPage = await client.get(`${WP_URL}/wp-admin/post-new.php`);
    const nonceMatch = adminPage.data.match(/"nonce":"([a-zA-Z0-9]+)"/);
    if (!nonceMatch) {
        console.error("Failed to get WP API nonce");
        return;
    }
    const nonce = nonceMatch[1];
    client.defaults.headers.common['X-WP-Nonce'] = nonce;
    console.log("Nonce obtained: " + nonce);

    async function getOrCreateTag(tagName) {
        try {
            const searchRes = await client.get(`${WP_URL}/wp-json/wp/v2/tags?search=${encodeURIComponent(tagName)}`);
            if (searchRes.data.length > 0) {
                const exactMatch = searchRes.data.find(t => t.name === tagName);
                if (exactMatch) return exactMatch.id;
            }
            const createRes = await client.post(`${WP_URL}/wp-json/wp/v2/tags`, { name: tagName });
            return createRes.data.id;
        } catch (e) {
            if (e.response && e.response.data && e.response.data.code === 'term_exists') {
                return e.response.data.data.term_id;
            }
            console.error(`Error creating tag ${tagName}:`, e.message);
            return null;
        }
    }

    const targets = JSON.parse(fs.readFileSync('target_posts.json', 'utf8'));
    console.log(`Processing ${targets.length} posts...`);
    for (let post of targets) {
        let contentToUpdate = null;
        if (post.isShort) {
            const filename = `article_${post.id}.html`;
            if (fs.existsSync(filename)) {
                contentToUpdate = fs.readFileSync(filename, 'utf8');
            } else {
                console.log(`Missing HTML file for post ${post.id}`);
            }
        }

        let tagsToAssign = [];
        if (post.noTags || post.isShort) {
            let cleanedTitle = post.title.replace(/\[.*?\]/g, '').replace(/[^\w가-힣\s]/g, '');
            let words = cleanedTitle.split(/\s+/).filter(w => w.length >= 2);
            for (let word of words) {
                const tagId = await getOrCreateTag(word);
                if (tagId) tagsToAssign.push(tagId);
            }
        }

        let updateData = {};
        if (contentToUpdate) updateData.content = contentToUpdate;
        if (tagsToAssign.length > 0) updateData.tags = tagsToAssign;

        if (Object.keys(updateData).length > 0) {
            try {
                await client.post(`${WP_URL}/wp-json/wp/v2/posts/${post.id}`, updateData);
                console.log(`Updated post ${post.id} - ${post.title}`);
            } catch (e) {
                console.error(`Failed to update post ${post.id}:`, e.response ? e.response.data : e.message);
            }
        }
    }
    console.log("All done!");
}

main();

