const { chromium } = require('playwright');
const fs = require('fs');
require('dotenv').config();

const WP_URL = process.env.WP_URL || 'https://100plus.kr';
const WP_USER = process.env.WP_USER || 'wide1002@gmail.com';
const WP_PASS = process.env.WP_PASS || 'g7bakkyWMD';
const DELAY_BETWEEN_POSTS = 10 * 60 * 1000; // 10 minutes
const RETRY_DELAY = 60 * 60 * 1000; // 1 hour

function logMsg(msg) {
    const timestamp = new Date().toISOString();
    const line = `[${timestamp}] ${msg}`;
    console.log(line);
    fs.appendFileSync('autonomous_updater.log', line + '\n');
}

function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

async function checkSiteReachable() {
    try {
        const fetch = (await import('node-fetch')).default;
        const res = await fetch(WP_URL, { timeout: 15000 });
        return res.ok || res.status === 401 || res.status === 403; // Even if 403, we might bypass it with browser. But if it times out, it throws.
    } catch (e) {
        return false;
    }
}

async function updateSinglePost(post) {
    logMsg(`Starting update for post ${post.id}: ${post.title}`);
    let browser;
    try {
        browser = await chromium.launch({ headless: true });
        const context = await browser.newContext({
            userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/115.0.0.0 Safari/537.36'
        });
        const page = await context.newPage();

        logMsg(`[Post ${post.id}] Navigating to login...`);
        await page.goto(`${WP_URL}/wp-login.php`, { waitUntil: 'domcontentloaded', timeout: 30000 });

        try {
            await page.waitForSelector('#user_login', { timeout: 15000 });
            await page.fill('#user_login', WP_USER);
            await page.fill('#user_pass', WP_PASS);
            await Promise.all([
                page.waitForNavigation({ waitUntil: 'domcontentloaded', timeout: 30000 }),
                page.click('#wp-submit')
            ]);
            logMsg(`[Post ${post.id}] Logged in successfully.`);
        } catch (e) {
            logMsg(`[Post ${post.id}] Login form not found or already logged in. URL: ${page.url()}`);
            if (page.url().includes('wp-login.php')) {
                throw new Error("Stuck on login page. IP might still be blocked by JS challenge.");
            }
        }

        logMsg(`[Post ${post.id}] Navigating to post-new.php for nonce...`);
        await page.goto(`${WP_URL}/wp-admin/post-new.php`, { waitUntil: 'domcontentloaded', timeout: 30000 });

        const result = await page.evaluate(async (post) => {
            const nonce = window.wpApiSettings ? window.wpApiSettings.nonce : null;
            if (!nonce) return { success: false, error: "No nonce found" };

            const headers = {
                'X-WP-Nonce': nonce,
                'Content-Type': 'application/json',
                'Accept': 'application/json'
            };

            async function getOrCreateTag(tagName) {
                try {
                    const searchRes = await fetch(`/wp-json/wp/v2/tags?search=${encodeURIComponent(tagName)}`, { headers });
                    const searchData = await searchRes.json();
                    if (searchData.length > 0) {
                        const exactMatch = searchData.find(t => t.name === tagName);
                        if (exactMatch) return exactMatch.id;
                    }
                    const createRes = await fetch(`/wp-json/wp/v2/tags`, {
                        method: 'POST',
                        headers,
                        body: JSON.stringify({ name: tagName })
                    });
                    const createData = await createRes.json();
                    if (createData.id) return createData.id;
                    if (createData.code === 'term_exists') return createData.data.term_id;
                } catch (e) {
                    return null; // Ignore tag errors
                }
                return null;
            }

            let tagsToAssign = [];
            if (post.tagsToAssignNames) {
                for (let tagName of post.tagsToAssignNames) {
                    let tagId = await getOrCreateTag(tagName);
                    if (tagId) tagsToAssign.push(tagId);
                }
            }

            let updateData = {};
            if (post.contentToUpdate) updateData.content = post.contentToUpdate;
            if (tagsToAssign.length > 0) updateData.tags = tagsToAssign;

            if (Object.keys(updateData).length > 0) {
                try {
                    const updateRes = await fetch(`/wp-json/wp/v2/posts/${post.id}`, {
                        method: 'POST',
                        headers,
                        body: JSON.stringify(updateData)
                    });
                    const updateDataRes = await updateRes.json();
                    if (updateDataRes.id) {
                        return { success: true };
                    } else {
                        return { success: false, error: JSON.stringify(updateDataRes) };
                    }
                } catch (e) {
                    return { success: false, error: e.message };
                }
            }
            return { success: true, note: "No updates needed" };
        }, post);

        if (result.success) {
            logMsg(`[Post ${post.id}] Update successful!`);
            return true;
        } else {
            logMsg(`[Post ${post.id}] Update failed: ${result.error}`);
            return false;
        }
    } catch (err) {
        logMsg(`[Post ${post.id}] Browser error: ${err.message}`);
        return false;
    } finally {
        if (browser) await browser.close();
    }
}

async function main() {
    logMsg("Autonomous updater started. User requested to wait 1 hour before checking, then 1 hour retries.");

    // Load targets
    let targets = JSON.parse(fs.readFileSync('target_posts.json', 'utf8'));
    for (let post of targets) {
        if (post.isShort) {
            const filename = `article_${post.id}.html`;
            if (fs.existsSync(filename)) {
                post.contentToUpdate = fs.readFileSync(filename, 'utf8');
            }
        }
        if (post.noTags || post.isShort) {
            let cleanedTitle = post.title.replace(/\[.*?\]/g, '').replace(/[^\w가-힣\s]/g, '');
            post.tagsToAssignNames = cleanedTitle.split(/\s+/).filter(w => w.length >= 2);
        }
    }

    logMsg(`Total posts to update: ${targets.length}`);

    // Initial 1 hour wait as requested
    logMsg("Waiting 1 hour before first attempt...");
    await sleep(RETRY_DELAY);

    let siteUp = false;
    while (!siteUp) {
        logMsg("Checking if site is reachable...");
        const reachable = await checkSiteReachable();
        if (reachable) {
            logMsg("Site is reachable! Proceeding with updates.");
            siteUp = true;
        } else {
            logMsg("Site is still unreachable (IP likely still blocked). Waiting another 1 hour...");
            await sleep(RETRY_DELAY);
        }
    }

    for (let i = 0; i < targets.length; i++) {
        const post = targets[i];
        let success = false;
        let attempts = 0;

        while (!success && attempts < 3) {
            attempts++;
            success = await updateSinglePost(post);
            if (!success) {
                logMsg(`Attempt ${attempts} failed for post ${post.id}. Waiting 5 mins before retry...`);
                await sleep(5 * 60 * 1000); 
            }
        }

        if (i < targets.length - 1) {
            logMsg(`Waiting 10 minutes before the next post... (${i+1}/${targets.length} completed)`);
            await sleep(DELAY_BETWEEN_POSTS);
        }
    }

    logMsg("All autonomous updates completed!");
}

main().catch(e => logMsg("Fatal error: " + e.message));

