// Define the images and keywords
const mappings = [
    { keyword: '거북목', file: 'turtle_neck_1781826565742.png' },
    { keyword: '족저근막염', file: 'plantar_fasciitis_1781826574858.png' },
    { keyword: '오십견', file: 'frozen_shoulder_1781826586578.png' },
    { keyword: '세로토닌', file: 'depression_serotonin_1781826598696.png' },
    { keyword: '크릴오일', file: 'krill_omega_1781826610781.png' }
];

async function main() {
    console.log("Reading target_posts.json to find Post IDs...");
    const targets = JSON.parse(fs.readFileSync('target_posts.json', 'utf8'));

    const tasks = [];
    for (let m of mappings) {
        const post = targets.find(t => t.title.includes(m.keyword));
        if (post) {
            tasks.push({ postId: post.id, title: post.title, file: path.join(artifactDir, m.file) });
        } else {
            console.error(`Post not found for keyword: ${m.keyword}`);
        }
    }

    if (tasks.length === 0) return console.log("No tasks found.");

    console.log(`Found ${tasks.length} posts to update. Launching browser...`);
    const browser = await chromium.launch({ headless: true });
    const context = await browser.newContext({
        userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) Chrome/115.0.0.0 Safari/537.36'
    });
    const page = await context.newPage();

    console.log("Logging into WordPress...");
    await page.goto(`${WP_URL}/wp-login.php`, { waitUntil: 'domcontentloaded' });
    await page.fill('#user_login', WP_USER);
    await page.fill('#user_pass', WP_PASS);
    await Promise.all([
        page.waitForNavigation({ waitUntil: 'domcontentloaded' }),
        page.click('#wp-submit')
    ]);

    console.log("Fetching API nonce...");
    await page.goto(`${WP_URL}/wp-admin/post-new.php`, { waitUntil: 'domcontentloaded' });
    const nonce = await page.evaluate(() => window.wpApiSettings ? window.wpApiSettings.nonce : null);

    if (!nonce) {
        console.error("Failed to get nonce.");
        await browser.close();
        return;
    }

    console.log("Uploading images and updating posts...");
    for (const task of tasks) {
        console.log(`\nProcessing Post ${task.postId}: ${task.title}`);
        try {
            const imageBuffer = fs.readFileSync(task.file);
            const fileName = path.basename(task.file);

            console.log(`- Uploading ${fileName}...`);
            const uploadRes = await context.request.post(`${WP_URL}/wp-json/wp/v2/media`, {
                headers: {
                    'X-WP-Nonce': nonce,
                    'Content-Disposition': `attachment; filename="${fileName}"`,
                    'Content-Type': 'image/png'
                },
                data: imageBuffer
            });

            if (!uploadRes.ok()) {
                console.error(`Upload failed: ${uploadRes.status()} ${await uploadRes.text()}`);
                continue;
            }

            const mediaData = await uploadRes.json();
            const mediaId = mediaData.id;
            console.log(`- Uploaded successfully. Media ID: ${mediaId}`);

            console.log(`- Setting as featured image for Post ${task.postId}...`);
            const updateRes = await context.request.post(`${WP_URL}/wp-json/wp/v2/posts/${task.postId}`, {
                headers: {
                    'X-WP-Nonce': nonce,
                    'Content-Type': 'application/json'
                },
                data: { featured_media: mediaId }
            });

            if (updateRes.ok()) {
                console.log(`- Post updated successfully!`);
            } else {
                console.error(`- Post update failed: ${updateRes.status()} ${await updateRes.text()}`);
            }

            await new Promise(r => setTimeout(r, 2000)); // Small delay
        } catch (e) {
            console.error(`Error processing post ${task.postId}: ${e.message}`);
        }
    }

    await browser.close();
    console.log("\nAll image replacement tasks completed!");
}

main().catch(console.error);

