const WP_URL = process.env.WP_URL || 'https://100plus.kr';
const WP_USER = process.env.WP_USER || 'wide1002@gmail.com';
const WP_PASS = process.env.WP_PASS || 'g7bakkyWMD';

const adsenseCode = `<script async src="https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=ca-pub-7353150751712262" crossorigin="anonymous"></script>`;

async function main() {
    console.log("Launching browser...");
    const browser = await chromium.launch({ headless: true });
    const context = await browser.newContext({
        userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) Chrome/115.0.0.0 Safari/537.36'
    });
    const page = await context.newPage();

    console.log("Logging into WordPress...");
    await page.goto(`${WP_URL}/wp-login.php`, { waitUntil: 'domcontentloaded' });
    await page.fill('#user_login', WP_USER);
    await page.fill('#user_pass', WP_PASS);
    await Promise.all([
        page.waitForNavigation({ waitUntil: 'domcontentloaded' }),
        page.click('#wp-submit')
    ]);

    console.log("Navigating to WPCode Global Headers & Footers...");
    await page.goto(`${WP_URL}/wp-admin/admin.php?page=wpcode-headers-footers`, { waitUntil: 'networkidle' });

    console.log("Injecting AdSense code...");
    const success = await page.evaluate((code) => {
        try {
            // WPCode uses CodeMirror
            const cmWrappers = document.querySelectorAll('.CodeMirror');
            if (cmWrappers.length > 0 && cmWrappers[0].CodeMirror) {
                const cm = cmWrappers[0].CodeMirror; // Header is usually the first one
                const currentVal = cm.getValue();
                if (!currentVal.includes('adsbygoogle')) {
                    cm.setValue(currentVal + '\n\n<!-- Google AdSense -->\n' + code);
                }
                return true;
            }
            // Fallback to standard textarea if CodeMirror is disabled
            const headerTextarea = document.querySelector('textarea[name="wpcode_settings[header]"]');
            if (headerTextarea) {
                if (!headerTextarea.value.includes('adsbygoogle')) {
                    headerTextarea.value += '\n\n<!-- Google AdSense -->\n' + code;
                }
                return true;
            }
            return false;
        } catch (e) {
            return false;
        }
    }, adsenseCode);

    if (success) {
        console.log("Code injected. Saving changes...");
        await Promise.all([
            page.waitForNavigation({ waitUntil: 'domcontentloaded' }),
            page.click('button[type="submit"].wpcode-button') // Save changes button in WPCode
        ]);
        console.log("AdSense code successfully added and saved!");
    } else {
        console.error("Failed to find the WPCode Header editor.");
    }

    await browser.close();
}

main().catch(console.error);

